"""Router for Role — generated by BackendAgent."""
from __future__ import annotations

from fastapi import APIRouter, HTTPException

from schemas import RoleCreate, RoleUpdate, RoleResponse
from services import RoleService

router = APIRouter()
_service = RoleService()


@router.get("/", response_model=list[RoleResponse])
def list_roles() -> list:
    """List all roles."""
    return _service.list_roles()


@router.post("/", response_model=RoleResponse, status_code=201)
def create_role(data: RoleCreate) -> object:
    """Create a new role."""
    try:
        return _service.create_role(data.model_dump())
    except NotImplementedError:
        raise HTTPException(status_code=501, detail="Not yet implemented")


@router.get("/{id}", response_model=RoleResponse)
def get_role(id: str) -> object:
    """Get a single role by id."""
    item = _service.get_role(id)
    if item is None:
        raise HTTPException(status_code=404, detail="Role not found")
    return item


@router.put("/{id}", response_model=RoleResponse)
def update_role(id: str, data: RoleUpdate) -> object:
    """Update an existing role."""
    try:
        result = _service.update_role(id, data.model_dump(exclude_unset=True))
    except NotImplementedError:
        raise HTTPException(status_code=501, detail="Not yet implemented")
    if result is None:
        raise HTTPException(status_code=404, detail="Role not found")
    return result


@router.delete("/{id}", status_code=204)
def delete_role(id: str) -> None:
    """Delete a role. Level-3 action — requires permission check."""
    if not _service.delete_role(id):
        raise HTTPException(status_code=404, detail="Role not found")
